1	import { lazy, Suspense } from 'react';
2	import { createBrowserRouter, Navigate } from 'react-router-dom';
3	import { BlankLayout } from '@/layouts/BlankLayout';
4	import { MainLayout } from '@/layouts/MainLayout';
5	import { ProtectedRoute } from './ProtectedRoute';
6	
7	/**
8	 * @template {Record<string, unknown>} TModule
9	 * @param {() => Promise<TModule>} loader
10	 * @param {keyof TModule} exportName
11	 * @returns {import('react').LazyExoticComponent<import('react').ComponentType<any>>}
12	 */
13	const lazyNamed = (loader, exportName) =>
14	    lazy(() => loader().then((module) => ({ default: module[exportName] })));
15	
16	const LoginPage = lazyNamed(() => import('@/features/auth/LoginPage'), 'LoginPage');
17	const HomePage = lazyNamed(() => import('@/features/home/HomePage'), 'HomePage');
18	const DomainListPage = lazyNamed(() => import('@/features/domain/DomainListPage'), 'DomainListPage');
19	const WordListPage = lazyNamed(() => import('@/features/word/WordListPage'), 'WordListPage');
20	const ForbiddenListPage = lazyNamed(() => import('@/features/forbidden/ForbiddenListPage'), 'ForbiddenListPage');
21	const UploadPage = lazyNamed(() => import('@/features/import/UploadPage'), 'UploadPage');
22	const DetailPage = lazyNamed(() => import('@/features/import/DetailPage'), 'DetailPage');
23	
24	const loadingFallback = <div className='p-6 text-sm text-muted-foreground'>불러오는 중...</div>;
25	
26	/**
27	 * @param {import('react').ReactNode} element
28	 * @returns {JSX.Element}
29	 */
30	const withSuspense = (element) => <Suspense fallback={loadingFallback}>{element}</Suspense>;
31	
32	export const router = createBrowserRouter([
33	    {
34	        element: <BlankLayout />,
35	        children: [{ path: '/login', element: withSuspense(<LoginPage />), handle: { breadcrumb: '로그인' } }],
36	    },
37	    {
38	        element: (
39	            <ProtectedRoute>
40	                <MainLayout />
41	            </ProtectedRoute>
42	        ),
43	        children: [
44	            { index: true, element: <Navigate to="/home" replace /> },
45	            { path: '/home', element: withSuspense(<HomePage />), handle: { breadcrumb: '홈' } },
46	            { path: '/domain', element: withSuspense(<DomainListPage />), handle: { breadcrumb: '도메인' } },
47	            { path: '/word', element: withSuspense(<WordListPage />), handle: { breadcrumb: '단어' } },
48	            { path: '/forbidden', element: withSuspense(<ForbiddenListPage />), handle: { breadcrumb: '금칙어' } },
49	            {
50	                path: '/import',
51	                element: withSuspense(<UploadPage />),
52	                handle: { breadcrumb: '데이터 가져오기' },
53	            },
54	            {
55	                path: '/import/:historyId',
56	                element: withSuspense(<DetailPage />),
57	                handle: {
58	                    breadcrumb: ({ params }) =>
59	                        params.historyId ? `상세 #${params.historyId}` : '상세',
60	                },
61	            },
62	        ],
63	    },
64	    {
65	        path: '*',
66	        element: <Navigate to="/home" replace />,
67	    },
68	]);
